import React, { useState, useEffect } from 'react';

function VebaCard() {
  const [veba, setVeba] = useState(null);
  const [vebaLoading, setVebaLoading] = useState(true);

  useEffect(() => {
    const fetchVeba = async () => {
      try {
        const response = await fetch('http://127.0.0.1:5000/veba/statistics');
        const json = await response.json();
        // IMPORTANT: Extract the 'data' property from the response
        setVeba(json.data);
        setVebaLoading(false);
      } catch (error) {
        console.error('Error fetching VEBA statistics:', error);
        setVebaLoading(false);
      }
    };

    fetchVeba();
    const interval = setInterval(fetchVeba, 30000); // Refresh every 30s
    return () => clearInterval(interval);
  }, []);

  return (
    <Card title="VEBA Governance • Leakage Prevention" subtitle={vebaLoading ? "Loading…" : "Listings + tendering"}>
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-2">
        <MiniStat 
          label="Bookings today" 
          value={vebaLoading || !veba || !veba.bookings_today ? "—" : veba.bookings_today.toLocaleString()} 
        />
        <MiniStat 
          label="Leakage attempts" 
          value={vebaLoading || !veba || !veba.leakage_attempts ? "—" : veba.leakage_attempts.toLocaleString()} 
        />
        <MiniStat 
          label="Settlement p95" 
          value={vebaLoading || !veba || !veba.settlement_p95 ? "—" : veba.settlement_p95} 
        />
      </div>
    </Card>
  );
}
